import json

SOURCE_PRIORITY = {'XPHB': 4, 'PHB2024': 4, 'TCE': 3, 'XGE': 3, 'MPMM': 2, 'PHB': 1}

def dedupe\(items\):
    best = {}
    for item in items:
        name = item['name']
        priority = SOURCE_PRIORITY.get\(item.get\('source', ''\), 0\)
        if name not in best or priority > SOURCE_PRIORITY.get\(best[name].get\('source', ''\), 0\):
            best[name] = item
    return sorted\(best.values\(\), key=lambda x: x['name']\)

with open\('data/game_data.json'\) as f:
    data = json.load\(f\)

for edition in data:
    for key in ['races', 'classes', 'backgrounds']:
        before = len\(data[edition][key]\)
        data[edition][key] = dedupe\(data[edition][key]\)
        after = len\(data[edition][key]\)
        print\(f'{edition} {key}: {before} -> {after}'\)

with open\('data/game_data.json', 'w'\) as f:
    json.dump\(data, f, indent=2\)

print\('Done.'\)
